```class Solution {
public:
    int lengthOfLongestSubstring(string s) {
        int n = s.length();
        int maxLengthSoFar = 0;
        int currLength = 1;
        set<char> seen;

        for (int i = 0; i < n; i++) {
            if (seen.find(s[i]) != seen.end()) {
                seen.erase(s[currLength - 1]);
                currLength--;
            }
            seen.insert(s[i]);
            maxLengthSoFar = max(maxLengthSoFar, currLength + 1);
        }

        return maxLengthSoFar;
    }
};
```

